19	const TELEGRAM_INTERACTIVE_ROW_SIZE = 3;
20	
21	function toTelegramButtonStyle(
22	  style?: InteractiveReplyButton["style"],
23	): TelegramInlineButton["style"] {
24	  return style === "danger" || style === "success" || style === "primary" ? style : undefined;
25	}
26	
27	function chunkInteractiveButtons(
28	  buttons: readonly InteractiveReplyButton[],
29	  rows: TelegramInlineButton[][],
30	) {
31	  for (let i = 0; i < buttons.length; i += TELEGRAM_INTERACTIVE_ROW_SIZE) {
32	    const row = buttons.slice(i, i + TELEGRAM_INTERACTIVE_ROW_SIZE).flatMap((button) => {
33	      const callbackData = sanitizeTelegramCallbackData(button.value);
34	      if (!callbackData) {
35	        return [];
36	      }
37	      return [
38	        {
39	          text: button.label,
40	          callback_data: callbackData,
41	          style: toTelegramButtonStyle(button.style),
42	        },
43	      ];
44	    });
45	    if (row.length > 0) {
46	      rows.push(row);
47	    }
48	  }
49	}
50	
51	export function buildTelegramInteractiveButtons(
52	  interactive?: InteractiveReply,
53	): TelegramInlineButtons | undefined {
54	  const rows = reduceInteractiveReply(
55	    interactive,
56	    [] as TelegramInlineButton[][],
57	    (state, block) => {
58	      if (block.type === "buttons") {
59	        chunkInteractiveButtons(block.buttons, state);
60	        return state;
61	      }
62	      if (block.type === "select") {
63	        chunkInteractiveButtons(
64	          block.options.map((option) => ({
65	            label: option.label,
66	            value: option.value,
67	          })),
68	          state,
69	        );
70	      }
71	      return state;
72	    },
73	  );
74	  return rows.length > 0 ? rows : undefined;
75	}
76	
77	export function resolveTelegramInlineButtons(params: {
78	  buttons?: TelegramInlineButtons;
79	  interactive?: unknown;
80	}): TelegramInlineButtons | undefined {
81	  return (
82	    params.buttons ?? buildTelegramInteractiveButtons(normalizeInteractiveReply(params.interactive))
83	  );
84	}
