  status: createComputedAccountStatusAdapter<ResolvedTelegramAccount, TelegramProbe, unknown>({
    defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
    collectStatusIssues: collectTelegramStatusIssues,
    buildChannelSummary: ({ snapshot }) => buildTokenChannelStatusSummary(snapshot),
    probeAccount: async ({ account, timeoutMs }) => /* probe bot health */,
    formatCapabilitiesProbe: ({ probe }) => /* format probe output */,
    auditAccount: async ({ account, timeoutMs, probe, cfg }) => /* audit groups */,
    resolveAccountSnapshot: ({ account, cfg, runtime, audit }) => /* snapshot state */,
  }),

  // Gateway (connection management)
  gateway: {
    startAccount: async (ctx) => {
      // Start polling or webhook listener
      return resolveTelegramMonitor()({
        token,
        accountId: account.accountId,
        config: ctx.cfg,
        runtime: ctx.runtime,
        abortSignal: ctx.abortSignal,
        useWebhook: Boolean(account.config.webhookUrl),
        webhookUrl: account.config.webhookUrl,
        // ... other webhook settings
      });
    },
    logoutAccount: async ({ accountId, cfg }) => {
      // Clear token from config
    },
  },
}
```

##### **5.2 Pairing** (text-based pairing)
```typescript
pairing: {
  text: {
    idLabel: "telegramUserId",
    message: PAIRING_APPROVED_MESSAGE,
    normalizeAllowEntry: createPairingPrefixStripper(/^(telegram|tg):/i),
    notify: async ({ cfg, id, message, accountId }) => {
      // Send pairing approval message to user
    },
  },
}
```

##### **5.3 Security**
```typescript
security: {
  dm: {
    channelKey: "telegram",
    resolvePolicy: (account) => account.config.dmPolicy,
    resolveAllowFrom: (account) => account.config.allowFrom,
    policyPathSuffix: "dmPolicy",
    normalizeEntry: (raw) => raw.replace(/^(telegram|tg):/i, ""),
  },
  collectWarnings: collectTelegramSecurityWarnings,
}
```

##### **5.4 Threading**
```typescript
threading: {
  topLevelReplyToMode: "telegram",
  buildToolContext: (params) => buildTelegramThreadingToolContext(params),
  resolveAutoThreadId: ({ to, toolContext, replyToId }) =>
    replyToId ? undefined : resolveTelegramAutoThreadId({ to, toolContext }),
}
```

##### **5.5 Outbound** (message sending)
```typescript
outbound: {
  base: {
    deliveryMode: "direct",
    chunker: (text, limit) => getTelegramRuntime().channel.text.chunkMarkdownText(text, limit),
    chunkerMode: "markdown",
    textChunkLimit: 4000,
    pollMaxOptions: 10,
    shouldSuppressLocalPayloadPrompt: ({ cfg, accountId, payload }) => /* suppress */,
    beforeDeliverPayload: async ({ cfg, target, hint }) => {
      // Send typing indicator for approval pending
    },
    shouldSkipPlainTextSanitization: ({ payload }) => Boolean(payload.channelData),
    resolveEffectiveTextChunkLimit: ({ fallbackLimit }) => Math.min(fallbackLimit, 4096),
    sendPayload: async ({ cfg, to, payload, /* ... */ }) => {
      // Send complete payload (text, media, buttons)
      const result = await sendTelegramPayloadMessages({ /* ... */ });
      return attachChannelToResult("telegram", result);
    },
  },

  attachedResults: {
    channel: "telegram",
    sendText: async (/* params */) => /* send text */,
    sendMedia: async (/* params */) => /* send media */,
    sendPoll: async (/* params */) => /* send poll */,
  },
}
```

---

### 6. **Type Definitions**

#### Key Types from `/src/bot-message-context.types.ts`:
```typescript
// Media reference with sticker metadata
type TelegramMediaRef = {
  path: string;
  contentType?: string;
  stickerMetadata?: StickerMetadata;
};

// Options for building message context
type TelegramMessageContextOptions = {
  commandSource?: "text" | "native";
  forceWasMentioned?: boolean;
  messageIdOverride?: string;
  receivedAtMs?: number;
  ingressBuffer?: "inbound-debounce" | "text-fragment";
};

// Parameters for message context building
type BuildTelegramMessageContextParams = {
  primaryCtx: TelegramContext;
  allMedia: TelegramMediaRef[];
  replyMedia?: TelegramMediaRef[];
  storeAllowFrom: string[];
  options?: TelegramMessageContextOptions;
  bot: Bot;
  cfg: OpenClawConfig;
  account: { accountId: string };
  historyLimit: number;
  groupHistories: Map<string, HistoryEntry[]>;
  dmPolicy: DmPolicy;
  allowFrom?: Array<string | number>;
  groupAllowFrom?: Array<string | number>;
  ackReactionScope: "off" | "none" | "group-mentions" | "group-all" | "direct" | "all";
  logger: TelegramLogger;
  resolveGroupActivation: ResolveGroupActivation;
  resolveGroupRequireMention: ResolveGroupRequireMention;
  resolveTelegramGroupConfig: ResolveTelegramGroupConfig;
  loadFreshConfig?: () => OpenClawConfig;
  upsertPairingRequest?: /* function type */;
  sendChatActionHandler: /* handler type */;
};
```

#### Button Types from `/src/button-types.ts`:
```typescript
type TelegramButtonStyle = "danger" | "success" | "primary";

type TelegramInlineButton = {
  text: string;
  callback_data: string;
  style?: TelegramButtonStyle;
};

type TelegramInlineButtons = ReadonlyArray<ReadonlyArray<TelegramInlineButton>>;
```

---

### 7. **Key Patterns**

#### **Reload Configuration Pattern (configPrefixes)**
The plugin uses configuration prefixes to track what should be reloaded:
- When token changes: Clears update offset to restart polling
- When account removed: Cleans up associated resources
- Prefix pattern: `channels.telegram` (global) or `channels.telegram.accounts.<accountId>` (per-account)

#### **Capabilities Object Structure**
The `messageToolCapabilities()` returns:
- `["inlineButtons"]` if inline buttons are enabled
- `[]` if disabled
- Determined by `resolveTelegramInlineButtonsScope()` config check

#### **Session Key Building**
- DM: `telegram:<chatId>` or `telegram:<chatId>:topic:<threadId>`
- Group: `telegram:group:<groupId>:<threadId>` (built with `buildTelegramGroupPeerId()`)
- Uses `buildOutboundBaseSessionKey()` from routing SDK

---

### 8. **Helper Functions Used**

The plugin delegates to many helper modules:
- **accounts.js** - Account resolution and listing
- **action-threading.js** - Auto thread ID detection
- **api-fetch.js** - Chat ID lookup from usernames
- **approval-native.js** - Approval capability implementation
- **audit.js** - Group membership verification
- **bot/helpers.js** - Group peer ID building
- **channel-actions.js** - Message action handlers
- **directory-config.js** - Directory peer/group listing
- **exec-approvals.js** - Execution approval flow
- **group-policy.js** - Group-specific policies
- **inline-buttons.js** - Button scope resolution
- **monitor.js** - Polling/webhook connection handler
- **normalize.js** - Target normalization
- **outbound-adapter.js** - Payload message sending
- **outbound-params.js** - Reply/thread ID parsing
- **probe.js** - Bot health check
- **reaction-level.js** - Reaction capability level
- **send.js** - Low-level message sending
- **session-conversation.js** - Session lookup
- **setup-core.js** - Setup configuration adapter
- **setup-surface.js** - Setup wizard UI
- **shared.js** - Common utilities and config adapter
- **status-issues.js** - Health check issues
- **targets.js** - Target ID parsing
- **thread-bindings.js** - Thread binding manager
- **threading-tool-context.js** - Threading context for tools

---

### 9. **Critical Integration Points**

1. **`createChatChannelPlugin()`** - Core SDK function that assembles all adapters
2. **`defineChannelPluginEntry()`** - Wraps the plugin for SDK discovery
3. **`defineSetupPluginEntry()`** - Wraps setup plugin
4. **`createPluginRuntimeStore()`** - Creates typed runtime store
5. **Config merging** - Supports global (`channels.telegram`) and per-account (`channels.telegram.accounts.<id>`) config
6. **Status snapshots** - Account health aggregated from probe, audit, and runtime state

---

### Summary

The Telegram plugin is a **fully-featured channel implementation** that demonstrates:
- Multi-account support with per-account configuration
- Advanced conversation binding (topic/thread support)
- Security policies (DM and group allowlists)
- Gateway management (polling vs webhook)
- Rich outbound capabilities (text, media, polls, inline buttons)
- Approval workflows
- Directory listing
- Status monitoring and health checks
- Runtime injection for testing and flexibility

